svg.script:
(function () {
  var svg = document.currentScript.ownerSVGElement || document.querySelector('svg');
  var items = svg.querySelectorAll('.sel');
  function select(el) {
    items.forEach(function (r) { r.classList.remove('selected'); });
    el.classList.add('selected');
    svg.dispatchEvent(new CustomEvent('regionselect', {
      detail: { region: el.getAttribute('data-region'),
                 label: el.getAttribute('aria-label') }
    }));
  }
  items.forEach(function (el) {
    el.addEventListener('click', function () { select(el); });
    el.addEventListener('keydown', function (e) {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); select(el); }
    });
  });
})();
